#!/usr/bin/env python3
import argparse
import base64
from pathlib import Path

TEMPLATE_B64 = ""


def main() -> None:
    parser = argparse.ArgumentParser(description="复制小红书 KOC/KOS 批量发布模板")
    parser.add_argument("output", nargs="?", default="小红书KOC-KOS批量定时发布模板.xlsx")
    args = parser.parse_args()
    target = Path(args.output).expanduser().resolve()
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_bytes(base64.b64decode(TEMPLATE_B64))
    print(target)


if __name__ == "__main__":
    main()

